<template><div class="page-container"><div class="page-card"><div class="page-header"><span class="page-title">商品类目</span><a-button type="primary" @click="onCreate"><plus-outlined/>添加类目</a-button></div><a-tree :tree-data="tree" default-expand-all :replace-fields="{children:'children',title:'name',key:'id'}"><template #title="{name,status}"><span>{{name}}</span><a-tag :color="status===1?'green':'default'" style="margin-left:8px">{{status===1?'启用':'禁用'}}</a-tag></template></a-tree></div></div></template>
<script setup lang="ts">import {ref,onMounted} from 'vue';import {message} from 'ant-design-vue';import {PlusOutlined} from '@ant-design/icons-vue';import {shopApi} from '@/api/shop';const tree=ref<any[]>([]);onMounted(async()=>{const r=await shopApi.getCategoryTree();tree.value=r.data.data});function onCreate(){message.info('添加类目')};
</script>
